INSERT INTO seed_skill VALUES
('database-engineer-architecture', 'Database Architecture', 'Architecture & System Design', 'Designing database boundaries, dependencies, replication patterns, reliability tradeoffs, and operational responsibilities.'),
('database-engineer-backend', 'Backend Data Access Patterns', 'Backend', 'Understanding how service behavior, transactions, query load, and connection patterns affect database design and operations.'),
('database-engineer-cybersecurity', 'Database Security Controls', 'Cybersecurity', 'Applying access control, encryption, audit evidence, risk reduction, and operational response for database systems.'),
('database-engineer-data-engineering', 'Database Support for Data Engineering', 'Data Engineering', 'Supporting pipeline-aware schemas, data quality checks, integration workloads, and analytical handoff requirements.'),
('database-engineer-database-design', 'Operational Database Design', 'Database', 'Designing schemas, constraints, indexes, and data access patterns that remain maintainable in production.'),
('database-engineer-database-normalization', 'Database Normalization', 'Database', 'Applying normal forms, dependency analysis, integrity constraints, and denormalization tradeoffs in relational models.'),
('database-engineer-performance-testing', 'Database Performance Testing', 'Software Quality', 'Designing repeatable workload tests, measuring latency and throughput, and comparing tuning changes with evidence.'),
('database-engineer-query-planning', 'Database Query Planning', 'Database', 'Reading query plans, identifying expensive operations, and validating query improvements with measured execution behavior.'),
('database-engineer-technical-writing', 'Database Operations Documentation', 'Career & Communication', 'Writing runbooks, migration notes, recovery steps, tuning decisions, and operational handoff documentation.'),
('database-engineer-transactions-and-isolation', 'Database Transactions and Isolation', 'Database', 'Managing transaction scope, isolation levels, lock behavior, anomalies, and consistency tradeoffs.'),
('database-engineer-indexing', 'Database Indexing', 'Database', 'Designing indexes around access patterns, query plans, write costs, and production performance constraints.'),
('database-engineer-replication', 'Replication for Database Operations', 'Database', 'Managing replication behavior, lag, failover risks, and operational recovery paths for production databases.'),
('database-engineer-automation', 'Database Operations Automation', 'DevOps & Platform', 'Automating repeatable database administration tasks with scripts, runbooks, change safety, and operational checks.');
