VALUES
('ph-database-engineering-role-and-foundations', NULL, 1, 'phase', NULL, NULL, NULL, 'Database Engineering Role and Foundations', 'This stage builds the database engineering role and foundations layer of the Database Engineer path.', 'Phase grouping for Database Engineering Role and Foundations.', 'trunk', 'roadmap-main', 1, 1, NULL, NULL, 100, 500, 1130, '{"role":"database-engineer","nodeKey":"ph-database-engineering-role-and-foundations"}'::jsonb, true, false, '["Database Engineering Role and Foundations"]'::jsonb, '["Required child nodes in this phase are completed."]'::jsonb),
('database-engineer-responsibilities', 'grp-database-engineering-role-and-foundations-foundations', 1, 'topic', NULL, NULL, NULL, 'Database Engineer Responsibilities', 'Apply database engineer responsibilities to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in Database Engineering Role and Foundations.', 'side', 'grp-database-engineering-role-and-foundations-foundations-support', 1, 1, 4, 'beginner', 70, 300, 1170, '{"role":"database-engineer","nodeKey":"database-engineer-responsibilities"}'::jsonb, true, true, '["Explain database engineer responsibilities using concrete examples.","Apply database engineer responsibilities to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates database engineer responsibilities with reviewable evidence."]'::jsonb),
('data-integrity-and-operational-safety', 'grp-database-engineering-role-and-foundations-foundations', 2, 'topic', NULL, NULL, NULL, 'Data Integrity and Operational Safety', 'Apply data integrity and operational safety to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in Database Engineering Role and Foundations.', 'choice', 'grp-database-engineering-role-and-foundations-foundations-topics', 1, 2, 4, 'beginner', 70, 700, 1170, '{"role":"database-engineer","nodeKey":"data-integrity-and-operational-safety"}'::jsonb, true, true, '["Explain data integrity and operational safety using concrete examples.","Apply data integrity and operational safety to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates data integrity and operational safety with reviewable evidence."]'::jsonb),
('relational-vs-non-relational-systems', 'grp-database-engineering-role-and-foundations-foundations', 3, 'topic', NULL, NULL, NULL, 'Relational vs Non-Relational Systems', 'Compare relational and non-relational systems by schema flexibility, consistency needs, query patterns, scaling model, and operational complexity.', 'Core topic in Database Engineering Role and Foundations.', 'choice', 'grp-database-engineering-role-and-foundations-foundations-topics', 1, 3, 4, 'beginner', 70, 300, 1280, '{"role":"database-engineer","nodeKey":"relational-vs-non-relational-systems"}'::jsonb, true, true, '["Match common workload needs to relational or non-relational storage choices.", "Explain tradeoffs without treating one model as universally better."]'::jsonb, '["A storage-choice comparison explains data model, access pattern, consistency, and operations tradeoffs."]'::jsonb),
('database-workload-types', 'grp-database-engineering-role-and-foundations-foundations', 4, 'topic', NULL, NULL, NULL, 'Database Workload Types', 'Classify workloads such as OLTP, OLAP, mixed operational reporting, batch ingestion, and event-heavy systems by access pattern and performance needs.', 'Core topic in Database Engineering Role and Foundations.', 'choice', 'grp-database-engineering-role-and-foundations-foundations-topics', 1, 4, 4, 'beginner', 70, 700, 1280, '{"role":"database-engineer","nodeKey":"database-workload-types"}'::jsonb, true, true, '["Identify workload types from query shape and usage pattern.", "Explain how workload type changes schema, indexing, and operations decisions."]'::jsonb, '["A workload profile summarizes read/write mix, concurrency, latency goals, and operational risks."]'::jsonb),
('database-environment-setup', 'grp-database-engineering-role-and-foundations-core-practice', 1, 'topic', NULL, NULL, NULL, 'Database Environment Setup', 'Apply database environment setup to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in Database Engineering Role and Foundations.', 'side', 'grp-database-engineering-role-and-foundations-core-practice-support', 1, 1, 4, 'beginner', 70, 300, 1290, '{"role":"database-engineer","nodeKey":"database-environment-setup"}'::jsonb, true, true, '["Explain database environment setup using concrete examples.","Apply database environment setup to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates database environment setup with reviewable evidence."]'::jsonb),
('database-documentation-practices', 'grp-database-engineering-role-and-foundations-core-practice', 2, 'topic', NULL, NULL, NULL, 'Database Documentation Practices', 'Document schemas, constraints, ownership, migration decisions, backup procedures, and operational runbooks so database changes are understandable and repeatable.', 'Core topic in Database Engineering Role and Foundations.', 'side', 'grp-database-engineering-role-and-foundations-core-practice-support', 1, 2, 3, 'beginner', 70, 700, 1290, '{"role":"database-engineer","nodeKey":"database-documentation-practices"}'::jsonb, true, true, '["Write documentation that supports safe database operation and change review.", "Connect documentation to ownership, recovery, and maintenance needs."]'::jsonb, '["A database documentation sample includes schema notes, runbook steps, and decision rationale."]'::jsonb),
('chk-database-engineering-role-and-foundations-review', 'grp-database-engineering-role-and-foundations-core-practice', 3, 'checkpoint', 'review', NULL, NULL, 'Database Engineering Role and Foundations Review', 'Validate the learner''s evidence for the database engineering role and foundations stage with explanations, artifacts, and next-step notes.', 'End-of-phase review checkpoint.', 'checkpoint', 'grp-database-engineering-role-and-foundations-core-practice-checkpoints', 1, 1, 2, 'intermediate', 65, 500, 1410, '{"role":"database-engineer","nodeKey":"chk-database-engineering-role-and-foundations-review"}'::jsonb, true, true, '["Review and explain the main work from Database Engineering Role and Foundations."]'::jsonb, '["Evidence is complete, reviewable, and tied to the phase outcomes."]'::jsonb),
('ph-sql-and-relational-modeling', NULL, 2, 'phase', NULL, NULL, NULL, 'SQL and Relational Modeling', 'This stage builds the sql and relational modeling layer of the Database Engineer path.', 'Phase grouping for SQL and Relational Modeling.', 'trunk', 'roadmap-main', 2, 2, NULL, NULL, 100, 500, 1710, '{"role":"database-engineer","nodeKey":"ph-sql-and-relational-modeling"}'::jsonb, true, false, '["SQL and Relational Modeling"]'::jsonb, '["Required child nodes in this phase are completed."]'::jsonb),
('relational-modeling-concepts', 'grp-sql-and-relational-modeling-foundations', 1, 'topic', NULL, NULL, NULL, 'Relational Modeling Concepts', 'Apply relational modeling concepts to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in SQL and Relational Modeling.', 'choice', 'grp-sql-and-relational-modeling-foundations-topics', 2, 1, 3, 'beginner', 70, 300, 1750, '{"role":"database-engineer","nodeKey":"relational-modeling-concepts"}'::jsonb, true, true, '["Explain relational modeling concepts using concrete examples.","Apply relational modeling concepts to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates relational modeling concepts with reviewable evidence."]'::jsonb),
('normalization-and-functional-dependencies', 'grp-sql-and-relational-modeling-foundations', 2, 'topic', NULL, NULL, NULL, 'Normalization and Functional Dependencies', 'Apply normalization and functional dependencies to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in SQL and Relational Modeling.', 'choice', 'grp-sql-and-relational-modeling-foundations-topics', 2, 2, 3, 'beginner', 70, 700, 1750, '{"role":"database-engineer","nodeKey":"normalization-and-functional-dependencies"}'::jsonb, true, true, '["Explain normalization and functional dependencies using concrete examples.","Apply normalization and functional dependencies to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates normalization and functional dependencies with reviewable evidence."]'::jsonb),
('keys-constraints-and-integrity', 'grp-sql-and-relational-modeling-foundations', 3, 'topic', NULL, NULL, NULL, 'Keys, Constraints, and Integrity', 'Apply keys, constraints, and integrity to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in SQL and Relational Modeling.', 'choice', 'grp-sql-and-relational-modeling-foundations-topics', 2, 3, 3, 'beginner', 70, 300, 1860, '{"role":"database-engineer","nodeKey":"keys-constraints-and-integrity"}'::jsonb, true, true, '["Explain keys, constraints, and integrity using concrete examples.","Apply keys, constraints, and integrity to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates keys, constraints, and integrity with reviewable evidence."]'::jsonb),
('advanced-sql-joins-and-subqueries', 'grp-sql-and-relational-modeling-foundations', 4, 'topic', NULL, NULL, NULL, 'Advanced SQL Joins and Subqueries', 'Write and review complex joins, subqueries, common table expressions, and set operations while checking correctness and query plan impact.', 'Core topic in SQL and Relational Modeling.', 'choice', 'grp-sql-and-relational-modeling-foundations-topics', 2, 4, 3, 'beginner', 70, 700, 1860, '{"role":"database-engineer","nodeKey":"advanced-sql-joins-and-subqueries"}'::jsonb, true, true, '["Use advanced SQL constructs to answer relational questions correctly.", "Review query plans for avoidable complexity or poor access patterns."]'::jsonb, '["A SQL exercise includes advanced joins or subqueries with expected results and a short plan review."]'::jsonb),
('window-functions-and-analytics-sql', 'grp-sql-and-relational-modeling-core-practice', 1, 'topic', NULL, NULL, NULL, 'Window Functions and Analytics SQL', 'Use SQL window functions for ranking, running totals, partitions, lag and lead comparisons, and operational reporting without losing row-level detail.', 'Core topic in SQL and Relational Modeling.', 'choice', 'grp-sql-and-relational-modeling-core-practice-topics', 2, 1, 3, 'beginner', 70, 300, 1870, '{"role":"database-engineer","nodeKey":"window-functions-and-analytics-sql"}'::jsonb, true, true, '["Write window-function queries for common reporting patterns.", "Explain partitioning and ordering choices in the query."]'::jsonb, '["A SQL script demonstrates at least three window-function patterns with validated outputs."]'::jsonb),
('schema-review-and-naming-standards', 'grp-sql-and-relational-modeling-core-practice', 2, 'topic', NULL, NULL, NULL, 'Schema Review and Naming Standards', 'Apply schema review and naming standards to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in SQL and Relational Modeling.', 'choice', 'grp-sql-and-relational-modeling-core-practice-topics', 2, 2, 3, 'beginner', 70, 700, 1870, '{"role":"database-engineer","nodeKey":"schema-review-and-naming-standards"}'::jsonb, true, true, '["Explain schema review and naming standards using concrete examples.","Apply schema review and naming standards to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates schema review and naming standards with reviewable evidence."]'::jsonb),
('chk-sql-and-relational-modeling-review', 'grp-sql-and-relational-modeling-core-practice', 4, 'checkpoint', 'review', NULL, NULL, 'SQL and Relational Modeling Review', 'Validate the learner''s evidence for the sql and relational modeling stage with explanations, artifacts, and next-step notes.', 'End-of-phase review checkpoint.', 'checkpoint', 'grp-sql-and-relational-modeling-core-practice-checkpoints', 2, 1, 2, 'intermediate', 65, 500, 1990, '{"role":"database-engineer","nodeKey":"chk-sql-and-relational-modeling-review"}'::jsonb, true, true, '["Review and explain the main work from SQL and Relational Modeling."]'::jsonb, '["Evidence is complete, reviewable, and tied to the phase outcomes."]'::jsonb),
('ph-postgresql-and-database-administration', NULL, 3, 'phase', NULL, NULL, NULL, 'PostgreSQL and Database Administration', 'This stage builds the postgresql and database administration layer of the Database Engineer path.', 'Phase grouping for PostgreSQL and Database Administration.', 'trunk', 'roadmap-main', 3, 3, NULL, NULL, 100, 500, 2290, '{"role":"database-engineer","nodeKey":"ph-postgresql-and-database-administration"}'::jsonb, true, false, '["PostgreSQL and Database Administration"]'::jsonb, '["Required child nodes in this phase are completed."]'::jsonb),
