('roles-privileges-and-access-control', 'grp-postgresql-and-database-administration-foundations', 3, 'topic', NULL, NULL, NULL, 'Roles, Privileges, and Access Control', 'Apply least-privilege access, authentication rules, encryption controls, and audit evidence for safer database operations.', 'Core topic in PostgreSQL and Database Administration.', 'choice', 'grp-postgresql-and-database-administration-foundations-topics', 3, 3, 3, 'beginner', 70, 300, 2440, '{"role":"database-engineer","nodeKey":"roles-privileges-and-access-control"}'::jsonb, true, true, '["Explain roles, privileges, and access control using concrete examples.","Apply roles, privileges, and access control to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates roles, privileges, and access control with reviewable evidence."]'::jsonb),
('extensions-and-procedural-features', 'grp-postgresql-and-database-administration-foundations', 4, 'topic', NULL, NULL, NULL, 'Extensions and Procedural Features', 'Apply extensions and procedural features to database design or operations with measurable checks, safe changes, and documented tradeoffs.', 'Core topic in PostgreSQL and Database Administration.', 'choice', 'grp-postgresql-and-database-administration-foundations-topics', 3, 4, 3, 'beginner', 70, 700, 2440, '{"role":"database-engineer","nodeKey":"extensions-and-procedural-features"}'::jsonb, true, true, '["Explain extensions and procedural features using concrete examples.","Apply extensions and procedural features to a realistic Database Engineer task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates extensions and procedural features with reviewable evidence."]'::jsonb),
